# Extract unique characters in order from CHARS_BY_FREQ
def extract_freq_list(s):
    seen = set()
    result = []
    for ch in s:
        if ch not in seen and '\u4e00' <= ch <= '\u9fff':
            seen.add(ch)
            result.append(ch)
    return result

import gzip
import io
import urllib.request
import urllib.error
import csv
import sys
import re

try:
    from pypinyin import pinyin, Style
    HAS_PYPINYIN = True
except ImportError:
    HAS_PYPINYIN = False
    print("WARNING: pypinyin not available", file=sys.stderr)

# ---------------------------------------------------------------------------
# 2. Fetch CC-CEDICT
# ---------------------------------------------------------------------------

def fetch_cedict():
    """Download and parse CC-CEDICT. Returns dict: simplified -> (pinyin_str, english_str)"""
    url = "https://www.mdbg.net/chinese/export/cedict/cedict_1_0_ts_utf-8_mdbg.txt.gz"
    print(f"Fetching CC-CEDICT from {url}...")
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        with urllib.request.urlopen(req, timeout=60) as resp:
            data = resp.read()
        print(f"Downloaded {len(data):,} bytes (gzipped)")
        with gzip.open(io.BytesIO(data)) as f:
            text = f.read().decode("utf-8")
        print(f"Decompressed: {len(text):,} chars")
    except Exception as e:
        print(f"ERROR fetching CC-CEDICT: {e}", file=sys.stderr)
        return {}

    result = {}
    line_re = re.compile(
        r'^(\S+)\s+(\S+)\s+\[([^\]]+)\]\s+/(.+)/$'
    )
    for line in text.splitlines():
        if line.startswith("#") or not line.strip():
            continue
        m = line_re.match(line)
        if not m:
            continue
        traditional, simplified, pinyins, meanings = m.groups()
        # Only single-character entries
        if len(simplified) != 1:
            continue
        # First meaning (strip leading/trailing spaces)
        first_meaning = meanings.split("/")[0].strip()
        # Keep the FIRST entry for each character (most common reading in CC-CEDICT)
        # Skip entries that look like variant/old/archaic forms
        if simplified in result:
            existing_pinyin, existing_meaning = result[simplified]
            # Prefer entries whose meaning doesn't start with "old variant" / "variant of"
            meaning_lower = first_meaning.lower()
            existing_lower = existing_meaning.lower()
            is_variant = any(kw in meaning_lower for kw in
                             ["variant of", "old variant", "archaic", "japanese", "erhua"])
            was_variant = any(kw in existing_lower for kw in
                              ["variant of", "old variant", "archaic", "japanese", "erhua"])
            # Replace if existing is variant and new is not
            if was_variant and not is_variant:
                result[simplified] = (pinyins, first_meaning)
            # Otherwise keep the first (don't overwrite)
        else:
            result[simplified] = (pinyins, first_meaning)
    print(f"CC-CEDICT: loaded {len(result):,} single-character entries")
    return result


def convert_pinyin(tone_num_str):
    """Convert CC-CEDICT tone-number pinyin to tone-mark pinyin using pypinyin lookup."""
    # CC-CEDICT pinyin uses tone numbers: "zhong1" or multiple readings "zhong1 zhong4"
    # We'll use the first reading and convert
    if not tone_num_str:
        return ""

    # Take first reading if multiple
    first = tone_num_str.split()[0]

    # Manual conversion table
    tone_map = {
        'a': ['ā','á','ǎ','à','a'],
        'e': ['ē','é','ě','è','e'],
        'i': ['ī','í','ǐ','ì','i'],
        'o': ['ō','ó','ǒ','ò','o'],
        'u': ['ū','ú','ǔ','ù','u'],
        'ü': ['ǖ','ǘ','ǚ','ǜ','ü'],
        'v': ['ǖ','ǘ','ǚ','ǜ','v'],
    }

    # Find tone number at end
    m = re.match(r'^([a-züv:]+)([1-5])$', first, re.IGNORECASE)
    if not m:
        return first

    syllable, tone_num = m.group(1), int(m.group(2))
    syllable = syllable.replace('u:', 'ü').replace('v', 'ü')

    if tone_num == 5:
        return syllable  # neutral tone, no mark

    # Rules for placement: a/e always get the mark; for ou, o gets it;
    # otherwise the last vowel gets it
    result_syl = list(syllable)
    placed = False

    # Priority: a, e
    for idx, ch in enumerate(result_syl):
        if ch in ('a', 'e', 'ā','á','ǎ','à','ē','é','ě','è'):
            base = 'a' if ch in ('a','ā','á','ǎ','à') else 'e'
            result_syl[idx] = tone_map[base][tone_num - 1]
            placed = True
            break

    if not placed:
        # ou -> o gets mark
        syl_str = ''.join(result_syl)
        if 'ou' in syl_str:
            idx = syl_str.index('o')
            result_syl[idx] = tone_map['o'][tone_num - 1]
            placed = True

    if not placed:
        # Last vowel
        for idx in range(len(result_syl) - 1, -1, -1):
            ch = result_syl[idx]
            if ch in ('i', 'o', 'u', 'ü', 'v'):
                base = ch if ch in tone_map else 'u'
                result_syl[idx] = tone_map[base][tone_num - 1]
                placed = True
                break

    return ''.join(result_syl)


def get_pypinyin(char):
    """Get pinyin for a character using pypinyin."""
    if not HAS_PYPINYIN:
        return ""
    try:
        result = pinyin(char, style=Style.TONE, heteronym=False)
        if result and result[0]:
            return result[0][0]
    except Exception:
        pass
    return ""


# ---------------------------------------------------------------------------
# 3. Fetch Jun Da's frequency list
# ---------------------------------------------------------------------------

def fetch_junda_freq():
    """
    Fetch Jun Da's character frequency list from MTSU.
    The page is GB2312-encoded and contains a <pre> block with tab-separated data:
      rank TAB char TAB frequency TAB cumulative% TAB pinyin TAB english<br>
    Returns list of (simplified) chars in frequency order.
    """
    url = "https://lingua.mtsu.edu/chinese-computing/statistics/char/list.php?Which=MO"
    print(f"Fetching frequency list from {url}...")
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        with urllib.request.urlopen(req, timeout=30) as resp:
            raw = resp.read()
        print(f"Downloaded frequency page: {len(raw):,} bytes")

        # Page is GB2312/GBK encoded
        try:
            html = raw.decode("gbk")
        except Exception:
            html = raw.decode("gb2312", errors="replace")

        # Find <pre> block - data is tab-separated lines ending with <br>
        pre_match = re.search(r'<pre>(.*?)</pre>', html, re.DOTALL | re.IGNORECASE)
        if not pre_match:
            print("Could not find <pre> block in page")
            return []

        pre_content = pre_match.group(1)
        print(f"Found <pre> block: {len(pre_content):,} chars")

        chars = []
        # Each line: rank\tchar\tfreq\tcumulative\tpinyin\tenglish<br>
        for line in re.split(r'<br\s*/?>', pre_content, flags=re.IGNORECASE):
            line = line.strip()
            if not line:
                continue
            parts = line.split('\t')
            if len(parts) >= 2:
                rank_str = parts[0].strip()
                char_str = parts[1].strip()
                if rank_str.isdigit() and len(char_str) == 1 and '\u4e00' <= char_str <= '\u9fff':
                    chars.append((int(rank_str), char_str))

        if chars:
            chars.sort(key=lambda x: x[0])
            seen = set()
            unique = []
            for _, ch in chars:
                if ch not in seen:
                    seen.add(ch)
                    unique.append(ch)
            print(f"Parsed {len(unique)} characters from Jun Da's frequency list")
            return unique
        else:
            print("Could not parse any characters from <pre> block")
            return []

    except Exception as e:
        print(f"ERROR fetching frequency list: {e}", file=sys.stderr)
        return []


# ---------------------------------------------------------------------------
# 4. Level assignment
# ---------------------------------------------------------------------------

LEVEL_RANGES = [
    (1,   200,  1),
    (201, 450,  2),
    (451, 750,  3),
    (751, 1100, 4),
    (1101,1500, 5),
    (1501,2000, 6),
    (2001,2700, 7),
    (2701,3500, 8),
    (3501,4200, 9),
    (4201,5000, 10),
]

def get_level(rank):
    for start, end, level in LEVEL_RANGES:
        if start <= rank <= end:
            return level
    return 10


# ---------------------------------------------------------------------------
# 5. Main
# ---------------------------------------------------------------------------

def main():
    output_path = "/Users/mom/chinese_learning_app/characters.csv"

    # Step 1: Load CC-CEDICT
    cedict = fetch_cedict()

    # Step 2: Get frequency list
    freq_chars = fetch_junda_freq()

    # Step 3: Supplement with fallback to reach 5000
    fallback_chars = extract_freq_list(CHARS_BY_FREQ)
    print(f"Fallback list has {len(fallback_chars)} unique characters")

    # Merge: start with web-fetched list, then add from fallback
    seen = set(freq_chars)
    combined = list(freq_chars)
    for ch in fallback_chars:
        if ch not in seen:
            seen.add(ch)
            combined.append(ch)

    # If still under 5000, add more characters from a broader Unicode CJK range
    # using common characters from cedict
    if len(combined) < 5000:
        print(f"Combined list has {len(combined)} chars, need more from CC-CEDICT...")
        # Add characters from cedict that aren't in our list yet
        # Sort cedict single chars by some heuristic (they're all single chars)
        for ch in cedict:
            if ch not in seen and '\u4e00' <= ch <= '\u9fff':
                seen.add(ch)
                combined.append(ch)
                if len(combined) >= 5000:
                    break

    # Trim to 5000
    combined = combined[:5000]
    print(f"Final character list: {len(combined)} characters")

    # Step 4: Build CSV
    rows = []
    for rank, char in enumerate(combined, 1):
        level = get_level(rank)

        # Get english from cedict; use pypinyin for pinyin (most accurate common reading)
        if char in cedict:
            raw_pinyin, english = cedict[char]
            # Prefer pypinyin for common reading; fall back to cedict conversion
            py = get_pypinyin(char)
            if not py:
                py = convert_pinyin(raw_pinyin)
        else:
            py = get_pypinyin(char)
            english = ""

        rows.append({
            "rank": rank,
            "character": char,
            "pinyin": py,
            "english": english,
            "level": level,
        })

    # Write CSV
    with open(output_path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=["rank","character","pinyin","english","level"])
        writer.writeheader()
        writer.writerows(rows)

    print(f"\nWrote {len(rows)} rows to {output_path}")

    # Verify and sample
    print("\n--- Verification ---")
    level_counts = {}
    for r in rows:
        lvl = r["level"]
        level_counts[lvl] = level_counts.get(lvl, 0) + 1
    for lvl in sorted(level_counts):
        print(f"  Level {lvl:2d}: {level_counts[lvl]} characters")

    print("\n--- Sample rows from each level ---")
    for lvl in range(1, 11):
        level_rows = [r for r in rows if r["level"] == lvl]
        if level_rows:
            sample = level_rows[0]
            print(f"  Level {lvl}: rank={sample['rank']} char={sample['character']} "
                  f"pinyin={sample['pinyin']} english={sample['english'][:40] if sample['english'] else ''}")


if __name__ == "__main__":
    main()
